const raw = $input.first().json;
function findVal(obj, ...keys) {
  for (const key of keys) {
    if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key];
  }
  const objKeys = Object.keys(obj);
  for (const key of keys) {
    const lower = key.toLowerCase();
    const found = objKeys.find(k => k.toLowerCase().replace(/[\s_-]/g, '') === lower.replace(/[\s_-]/g, ''));
    if (found && obj[found] !== undefined && obj[found] !== null && obj[found] !== '') return obj[found];
  }
  return null;
}
const d = raw.body || raw;
const assumptions = [];

const destination = findVal(d, 'destination', 'Destination', 'dest', 'city', 'place') || 'Goa, India';
if (!findVal(d, 'destination', 'Destination', 'dest', 'city', 'place')) assumptions.push('📍 Destination assumed: Goa, India');

const today = new Date();
const dayOfWeek = today.getDay();
const daysUntilSat = (6 - dayOfWeek + 7) % 7 || 7;
const nextSat = new Date(today); nextSat.setDate(today.getDate() + daysUntilSat);
const nextSun = new Date(nextSat); nextSun.setDate(nextSat.getDate() + 1);
const fmt = (dt) => dt.toISOString().split('T')[0];

let checkIn = findVal(d, 'check_in_date', 'checkInDate', 'checkin', 'start_date', 'Check In Date');
let checkOut = findVal(d, 'check_out_date', 'checkOutDate', 'checkout', 'end_date', 'Check Out Date');
if (!checkIn) { checkIn = fmt(nextSat); assumptions.push('📅 Check-in assumed: ' + checkIn + ' (next Saturday)'); }
if (!checkOut) { checkOut = fmt(nextSun); assumptions.push('📅 Check-out assumed: ' + checkOut + ' (next Sunday)'); }

const ensureDate = (s) => { if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s; try { const p = new Date(s); if (!isNaN(p)) return fmt(p); } catch(e){} return s; };
checkIn = ensureDate(checkIn); checkOut = ensureDate(checkOut);

let numNights = 2;
try { const ci=new Date(checkIn), co=new Date(checkOut); if(!isNaN(ci)&&!isNaN(co)) numNights=Math.max(1,Math.round((co-ci)/86400000)); } catch(e){}

let totalBudget = Number(findVal(d, 'total_budget', 'totalBudget', 'budget', 'Total Budget') || 0);
if (!totalBudget || totalBudget <= 0) { totalBudget = 55000; assumptions.push('💰 Budget assumed: ₹55,000 (range ₹50k-60k)'); }

let currency = findVal(d, 'currency', 'Currency') || 'INR';
if (!findVal(d, 'currency', 'Currency')) assumptions.push('💵 Currency: INR (default)');

let numTravelers = Number(findVal(d, 'num_travelers', 'numTravelers', 'travelers', 'guests', 'Number of Travelers') || 0);
if (!numTravelers || numTravelers <= 0) { numTravelers = 2; assumptions.push('👥 Travelers assumed: 2'); }

const email = findVal(d, 'email', 'Your Email', 'mail', 'emailAddress') || '';

const prefsRaw = findVal(d, 'preferences', 'Preferences', 'prefs', 'interests') || '';
const preferences = String(prefsRaw).split(',').map(s=>s.trim().toLowerCase()).filter(Boolean);
if (preferences.length === 0) { preferences.push('sightseeing','local food'); assumptions.push('🎯 Preferences assumed: sightseeing, local food'); }

let tripType = (findVal(d, 'trip_type', 'tripType', 'Trip Type', 'type') || 'leisure').toString().toLowerCase();
if (!findVal(d, 'trip_type', 'tripType', 'Trip Type', 'type')) assumptions.push('🏖️ Trip type assumed: Leisure');

return [{ json: { destination, check_in_date: checkIn, check_out_date: checkOut, num_nights: numNights, total_budget: totalBudget, currency, num_travelers: numTravelers, email, preferences, trip_type: tripType, assumptions } }];

const d = $input.first().json;
const totalBudget = Number(d.total_budget) || 55000;
const numNights = Number(d.num_nights) || 2;
const numTravelers = Number(d.num_travelers) || 2;
const hotelBudget = Math.round(totalBudget * 0.40);
const activityBudget = Math.round(totalBudget * 0.25);
const foodBudget = Math.round(totalBudget * 0.20);
const transportBudget = Math.round(totalBudget * 0.10);
const miscBudget = Math.round(totalBudget * 0.05);
const hotelPerNight = Math.round(hotelBudget / numNights);
const maxPricePerNight = Math.round(hotelPerNight / Math.ceil(numTravelers / 2));
return [{ json: { ...d, budget_breakdown: { hotel_total: hotelBudget, hotel_per_night: hotelPerNight, max_price_per_night: maxPricePerNight, activity_total: activityBudget, activity_per_day: Math.round(activityBudget / numNights), food_total: foodBudget, food_per_day: Math.round(foodBudget / numNights), transport_total: transportBudget, misc_total: miscBudget } } }];

const items = $input.all();
let hotels=[], places=[], activities=[], weather={}, reviewSnippets=[];
for (const item of items) {
  const d = item.json;
  if (d.properties && Array.isArray(d.properties)) hotels = d.properties;
  if (d.local_results && Array.isArray(d.local_results)) places = d.local_results;
  if (d.answer_box && (d.answer_box.type==='weather_result'||d.answer_box.temperature)) weather = d.answer_box;
  if (d.organic_results && Array.isArray(d.organic_results)) {
    const q = (d.search_parameters&&d.search_parameters.q)||'';
    if (q.includes('things to do')||q.includes('activities')) activities = d.organic_results;
    else if (q.includes('reviews')||q.includes('rated')) reviewSnippets = d.organic_results;
  }
  if (d.top_sights&&d.top_sights.sights) places = places.length>0 ? places : d.top_sights.sights;
}
const scoredHotels = hotels.filter(h=>h.rate_per_night||h.extracted_price).map(h=>({
  name:h.name||'Unknown', price_per_night:(h.rate_per_night&&h.rate_per_night.extracted_lowest)||h.extracted_price||0,
  total_price:(h.total_rate&&h.total_rate.extracted_lowest)||0, rating:h.overall_rating||0,
  reviews_count:h.reviews||0, score:(h.overall_rating||0)*Math.log10((h.reviews||1)+1),
  amenities:(h.amenities||[]).slice(0,6), link:h.link||''
})).sort((a,b)=>b.score-a.score).slice(0,5);
return [{json:{
  hotels:scoredHotels,
  places:(places||[]).slice(0,10).map(p=>({name:p.title||p.name||'',rating:p.rating||0,address:p.address||'',description:p.description||p.snippet||''})),
  activities:(activities||[]).slice(0,8).map(a=>({title:a.title||'',snippet:a.snippet||'',link:a.link||''})),
  weather, review_snippets:(reviewSnippets||[]).slice(0,5).map(r=>r.snippet||''),
  has_hotels_in_budget:scoredHotels.length>0, hotel_count:scoredHotels.length
}}];

const budgetData=$('Budget Calculator').first().json;
const research=$input.first().json;
return [{json:{plannerInput:JSON.stringify({user_request:{destination:budgetData.destination,check_in_date:budgetData.check_in_date,check_out_date:budgetData.check_out_date,num_nights:budgetData.num_nights,total_budget:budgetData.total_budget,currency:budgetData.currency,num_travelers:budgetData.num_travelers,preferences:budgetData.preferences||[],trip_type:budgetData.trip_type||'leisure'},budget_breakdown:budgetData.budget_breakdown,assumptions_made:budgetData.assumptions||[],research:{hotels:research.hotels,places:research.places,activities:research.activities,weather:research.weather,review_snippets:research.review_snippets}},null,2)}}];

const data=$input.first().json; let plan;
try { const raw=typeof data.output==='string'?data.output:JSON.stringify(data.output);
  try{plan=JSON.parse(raw)}catch(e1){let c=raw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
  try{plan=JSON.parse(c)}catch(e2){const m=c.match(/\{[\s\S]*\}/);if(m){plan=JSON.parse(m[0])}else{plan={raw_text:raw,parse_error:true,assumptions:[],recommended_hotel:{name:'Parse failed'},itinerary:[],budget_summary:{},packing_tips:[],travel_tips:[]}}}} }
catch(e){plan={raw_text:String(data.output||''),parse_error:true}}
return [{json:{plan}}];

